"""Log file parser for ERROR and WARNING entries."""
import re
from dataclasses import dataclass
from datetime import datetime
from typing import List, Optional


@dataclass
class LogEntry:
    timestamp: datetime
    level: str
    message: str

    @property
    def date_str(self) -> str:
        return self.timestamp.strftime("%Y-%m-%d")


_LOG_PATTERN = re.compile(
    r"(\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2})\s+(ERROR|WARNING)\s+(.*)"
)


def parse_line(line: str) -> Optional[LogEntry]:
    """Parse a single log line. Returns None if not ERROR/WARNING."""
    match = _LOG_PATTERN.match(line.strip())
    if not match:
        return None
    ts = datetime.strptime(match.group(1), "%Y-%m-%d %H:%M:%S")
    return LogEntry(timestamp=ts, level=match.group(2), message=match.group(3))

def parse_file(filepath: str) -> List[LogEntry]:
    """Parse a log file and return all ERROR/WARNING entries."""
    entries = []
    with open(filepath, "r") as f:
        for line in f:
            entry = parse_line(line)
            if entry is not None:
                entries.append(entry)
    return entries


def group_by_date(entries: List[LogEntry]) -> dict:
    """Group log entries by date string."""
    groups = defaultdict(list)
    for entry in entries:
        groups[entry.date_str].append(entry)
    return dict(sorted(groups.items()))

def generate_report(entries: List[LogEntry]) -> str:
    """Generate a summary report from log entries."""
    if not entries:
        return "No ERROR or WARNING entries found."
    groups = group_by_date(entries)
    lines = [f"Log Summary Report ({len(entries)} issues found)", "=" * 50]
    for date, items in groups.items():
        errors = sum(1 for e in items if e.level == "ERROR")
        warnings = sum(1 for e in items if e.level == "WARNING")
        lines.append(f"\n{date}: {errors} errors, {warnings} warnings")
        lines.append("-" * 30)
        for entry in items:
            time_str = entry.timestamp.strftime("%H:%M:%S")
            lines.append(f"  [{time_str}] {entry.level}: {entry.message}")
    return "\n".join(lines)
